from typing import Any, Text, Dict, List
from rasa_sdk import Action, Tracker
from rasa_sdk.executor import CollectingDispatcher
from rasa_sdk.events import SlotSet

# Mock database for demo purposes
PARCEL_DATABASE = {
    "PK12345": {
        "status": "In Transit",
        "location": "Lahore Distribution Center",
        "estimated_delivery": "2 days",
        "last_update": "2 hours ago"
    },
    "PK54321": {
        "status": "Out for Delivery",
        "location": "Islamabad Hub",
        "estimated_delivery": "Today by 6 PM",
        "last_update": "30 minutes ago"
    },
    "12345": {
        "status": "Delivered",
        "location": "Customer Location - Karachi",
        "estimated_delivery": "Delivered on Feb 14, 2026",
        "last_update": "Yesterday"
    }
}

BUS_SCHEDULES = {
    ("Lahore", "Islamabad"): [
        {"time": "09:00 AM", "type": "Express", "price": "Rs. 1500", "duration": "5 hours"},
        {"time": "02:00 PM", "type": "Standard", "price": "Rs. 1200", "duration": "6 hours"},
        {"time": "11:00 PM", "type": "Sleeper", "price": "Rs. 2000", "duration": "5 hours"}
    ],
    ("Lahore", "Karachi"): [
        {"time": "01:00 PM", "type": "Express", "price": "Rs. 3500", "duration": "18 hours"},
        {"time": "09:00 PM", "type": "Sleeper", "price": "Rs. 4000", "duration": "17 hours"}
    ],
    ("Islamabad", "Peshawar"): [
        {"time": "06:00 PM", "type": "Standard", "price": "Rs. 800", "duration": "3 hours"},
        {"time": "08:00 AM", "type": "Express", "price": "Rs. 1000", "duration": "2.5 hours"}
    ]
}

# --- PARCEL TRACKING ---
class ActionTrackParcel(Action):
    def name(self) -> Text:
        return "action_track_parcel"

    def run(self, dispatcher: CollectingDispatcher,
            tracker: Tracker,
            domain: Dict[Text, Any]) -> List[Dict[Text, Any]]:

        tracking_number = tracker.get_slot("tracking_number")

        if not tracking_number:
            dispatcher.utter_message(text="❌ Please provide a valid tracking number (e.g., PK12345 or 123456789)")
            return []

        # Look up parcel in mock database
        parcel_info = PARCEL_DATABASE.get(tracking_number.upper())

        if parcel_info:
            message = (
                f"📦 **Parcel Tracking: {tracking_number}**\n\n"
                f"✅ Status: {parcel_info['status']}\n"
                f"📍 Current Location: {parcel_info['location']}\n"
                f"🕐 Estimated Delivery: {parcel_info['estimated_delivery']}\n"
                f"🔄 Last Updated: {parcel_info['last_update']}"
            )
            dispatcher.utter_message(text=message)
        else:
            dispatcher.utter_message(
                text=f"❌ Sorry, I couldn't find any parcel with tracking number **{tracking_number}**.\n\n"
                     f"Please check the number and try again, or contact support if you need help."
            )

        return [SlotSet("tracking_number", None)]  # Clear slot for next query


# --- BUS SCHEDULE ---
class ActionShowBusSchedule(Action):
    def name(self) -> Text:
        return "action_show_bus_schedule"

    def run(self, dispatcher: CollectingDispatcher,
            tracker: Tracker,
            domain: Dict[Text, Any]) -> List[Dict[Text, Any]]:

        source = tracker.get_slot("source_city")
        destination = tracker.get_slot("destination_city")

        if not source or not destination:
            dispatcher.utter_message(
                text="Please provide both source and destination cities.\n"
                     "Example: 'Bus schedule from Lahore to Islamabad'"
            )
            return []

        # Normalize city names
        source = source.title()
        destination = destination.title()

        # Look up schedule
        route = (source, destination)
        schedules = BUS_SCHEDULES.get(route)

        if schedules:
            message = f"🚌 **Bus Schedule: {source} → {destination}**\n\n"
            for idx, bus in enumerate(schedules, 1):
                message += (
                    f"{idx}. {bus['time']} | {bus['type']} | {bus['price']} | {bus['duration']}\n"
                )
            dispatcher.utter_message(text=message)
        else:
            dispatcher.utter_message(
                text=f"❌ Sorry, no buses found for {source} → {destination}.\n\n"
                     f"Available routes: Lahore-Islamabad, Lahore-Karachi, Islamabad-Peshawar"
            )

        return [SlotSet("source_city", None), SlotSet("destination_city", None)]


